static bool cpu_detected = false;
static dap_cpu_features_t features;

static void detect_cpu_features(void) {
  if (cpu_detected) return;

#ifdef __x86_64__
  unsigned int eax, ebx, ecx, edx;
  __get_cpuid(1, &eax, &ebx, &ecx, &edx);
  features.has_sse2 = (edx & bit_SSE2) != 0;
  features.has_sse42 = (ecx & bit_SSE4_2) != 0;

  __get_cpuid(7, &eax, &ebx, &ecx, &edx);
  features.has_avx2 = (ebx & bit_AVX2) != 0;
#elif defined(__aarch64__)
  features.has_neon = true;
  features.has_sve = (getauxval(AT_HWCAP) & HWCAP_SVE) != 0;
#endif

  __atomic_store_n(&cpu_detected, true, __ATOMIC_RELEASE);
}

bool dap_cpu_has_avx2(void) {
  if (!cpu_detected) detect_cpu_features();
  return features.has_avx2;
}

