// Типы функций
typedef int (*json_parse_func_t)(const char* json);

// Реализации для разных платформ
int json_parse_avx2(const char* json);  // В arch/x86/json_avx2.c
int json_parse_sse42(const char* json); // В arch/x86/json_sse42.c
int json_parse_neon(const char* json);  // В arch/arm/json_neon.c
int json_parse_ref(const char* json);   // В arch/reference/json_ref.c

// Dispatcher
static json_parse_func_t select_parser(void) {
#ifdef __x86_64__
  if (dap_cpu_has_avx2()) return json_parse_avx2;
  if (dap_cpu_has_sse42()) return json_parse_sse42;
#elif defined(__aarch64__)
  if (dap_cpu_has_neon()) return json_parse_neon;
#endif
  return json_parse_ref;  // Fallback
}

// Public API
int json_parse(const char* json) {
  static json_parse_func_t parser = NULL;
  if (!parser) parser = select_parser();
  return parser(json);
}

// Реализации
static int json_parse_avx2(const char* json) { ... }
static int json_parse_sse42(const char* json) { ... }
static int json_parse_ref(const char* json) { ... }

// Resolver function
static void* json_parse_resolver(void) {
  if (dap_cpu_has_avx2()) return json_parse_avx2;
  if (dap_cpu_has_sse42()) return json_parse_sse42;
  return json_parse_ref;
}

// Public API с IFUNC
int json_parse(const char* json)
  __attribute__((ifunc("json_parse_resolver")));

