// Тест корректности: SIMD vs Reference
void test_simd_correctness(void) {
  const char* test_cases[] = {
    "{\"key\": \"value\"}",
    "[1, 2, 3, 4, 5]",
    // ... множество тест-кейсов
  };

  for (int i = 0; i < num_tests; i++) {
    json_t* ref_result = json_parse_ref(test_cases[i]);
    json_t* simd_result = json_parse_avx2(test_cases[i]);

    assert(json_equal(ref_result, simd_result));

    json_free(ref_result);
    json_free(simd_result);
  }
}

