// Benchmark разных impl
void benchmark_parsers(void) {
  const char* json = load_test_json();

  uint64_t start, end;

  // Reference
  start = rdtsc();
  for (int i = 0; i < iterations; i++) {
    json_t* result = json_parse_ref(json);
    json_free(result);
  }
  end = rdtsc();
  printf("Reference: %lu cycles\n", (end - start) / iterations);

  // SSE4.2
  start = rdtsc();
  for (int i = 0; i < iterations; i++) {
    json_t* result = json_parse_sse42(json);
    json_free(result);
  }
  end = rdtsc();
  printf("SSE4.2: %lu cycles\n", (end - start) / iterations);

  // AVX2
  start = rdtsc();
  for (int i = 0; i < iterations; i++) {
    json_t* result = json_parse_avx2(json);
    json_free(result);
  }
  end = rdtsc();
  printf("AVX2: %lu cycles\n", (end - start) / iterations);
}
